/// <summary>
/// Extension of the <c>SalesAgreementGenerateReleaseOrder</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(FormStr(SalesAgreementGenerateReleaseOrder))]
final class SalesAgreementGenerateReleaseOrder_Form_ETGSPAIN_Extension
{

}

Method.Source:
/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>This code is used to show or hide features in Spanish companies.</remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(SalesAgreementGenerateReleaseOrder, InventDim_inventBatchId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementGenerateReleaseOrder, InventDim_InventDimension1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementGenerateReleaseOrder, InventDim_inventSerialId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementGenerateReleaseOrder, InventDim_InventOwnerId_RU)).visible(currentCompanyIsSpanishCompany);

    if (currentCompanyIsSpanishCompany == NoYes::Yes)
    {
        SalesCreateReleaseOrderLineTmp_DS.object(fieldNum(SalesCreateReleaseOrderLineTmp, SalesQty)).mandatory(true);
        FormRealControl salesQty = this.design().controlName(formControlStr(SalesAgreementGenerateReleaseOrder, SalesCreateReleaseOrderLineTmp_SalesQty)) as FormRealControl;
        salesQty.allowNegative(true);
        InventDim_DS.object(fieldNum(InventDim, InventLocationId)).mandatory(true);
        InventDim_DS.object(fieldNum(InventDim, InventBatchId)).mandatory(true);
    }
}

/// <summary>
/// EventHandler to validate the warehouse in Spanish companies.
/// </summary>
/// <param name="sender">FormDataSource.</param>
/// <param name="e">FormDataSourceEventArgs.</param>
[FormDataSourceEventHandler(formDataSourceStr(SalesAgreementGenerateReleaseOrder, SalesCreateReleaseOrderLineTmp), FormDataSourceEventType::ValidatingWrite)]
public static void SalesCreateReleaseOrderLineTmp_OnValidatingWrite(FormDataSource sender, FormDataSourceEventArgs e)
{
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    if (currentCompanyIsSpanishCompany == NoYes::Yes)
    {
        var datasource = sender as FormDataSource;

        var args = e as FormDataSourceCancelEventArgs;

        if (args != null && datasource != null)
        {
            SalesCreateReleaseOrderLineTmp record = datasource.cursor() as SalesCreateReleaseOrderLineTmp;

            if (record.recId == 0)
            {
                InventDim inventDim = record.inventDim();

                if(!inventDim.InventLocationId)
                {
                    boolean doCancel = (Box::yesNo('@ETGSPAINLabels:PurchSalesAgreementGenerateReleaseOrderInventLocationIdWarning',DialogButton::Yes) == DialogButton::No);

                    args.cancel(doCancel);
                }
            }
        }
    }
}
